{
var input = inputs.Length > 0 ? inputs[0] : null;
        if (input is null)
            return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

        var mode = GetChoice(parameters, "mode", "boxBlur");
        var radius = Math.Max(1, GetInt(parameters, "radius", 1));
        var strength = GetFloat(parameters, "intensity", 1f);
        var mixRatio = GetFloat(parameters, "mixRatio", 1f);
        var embossAngle = GetFloat(parameters, "embossAngle", 135f) * MathF.PI / 180f;
        var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

        var (kernel, kernelSize, divisor) = BuildKernel(mode, radius, embossAngle);

        var w = input.Width;
        var h = input.Height;
        var result = new PixelBuffer(w, h);
        var halfK = kernelSize / 2;

        result.ParallelForEachPixel((x, y) =>
        {
            float sumR = 0, sumG = 0, sumB = 0;
            var (origR, origG, origB, origA) = input.GetPixel(x, y);

            if (mode == "outline")
            {
                // Combined Sobel magnitude: sqrt(Gx² + Gy²) per channel.
                // Uses 3x3 Sobel operators for both horizontal and vertical edge detection.
                float gxR = 0, gxG = 0, gxB = 0;
                float gyR = 0, gyG = 0, gyB = 0;
                for (var ky = 0; ky < 3; ky++)
                {
                    for (var kx = 0; kx < 3; kx++)
                    {
                        var sx = x + kx - 1;
                        var sy = y + ky - 1;
                        var (pr, pg, pb, _) = input.GetPixelWrapped(sx, sy);
                        // Sobel X: horizontal gradient
                        float wx = (kx == 0 ? -1f : kx == 2 ? 1f : 0f) * (ky == 0 ? -1f : ky == 2 ? 1f : 2f);
                        // Sobel Y: vertical gradient
                        float wy = (ky == 0 ? -1f : ky == 2 ? 1f : 0f) * (kx == 0 ? -1f : kx == 2 ? 1f : 2f);
                        gxR += pr * wx; gyR += pr * wy;
                        gxG += pg * wx; gyG += pg * wy;
                        gxB += pb * wx; gyB += pb * wy;
                    }
                }
                sumR = MathF.Sqrt(gxR * gxR + gyR * gyR);
                sumG = MathF.Sqrt(gxG * gxG + gyG * gyG);
                sumB = MathF.Sqrt(gxB * gxB + gyB * gyB);
            }
            else
            {
                for (var ky = 0; ky < kernelSize; ky++)
                {
                    for (var kx = 0; kx < kernelSize; kx++)
                    {
                        var sx = x + kx - halfK;
                        var sy = y + ky - halfK;
                        var (pr, pg, pb, _) = input.GetPixelWrapped(sx, sy);
                        var weight = kernel[ky * kernelSize + kx];
                        sumR += pr * weight;
                        sumG += pg * weight;
                        sumB += pb * weight;
                    }
                }
            }

            if (MathF.Abs(divisor) > 0.0001f && mode != "outline")
            {
                sumR /= divisor;
                sumG /= divisor;
                sumB /= divisor;
            }

            // Apply strength multiplier
            if (MathF.Abs(strength - 1f) > 0.001f)
            {
                sumR *= strength;
                sumG *= strength;
                sumB *= strength;
            }

            // Emboss: add 0.5 grey offset so flat areas map to mid-grey and
            // directional highlights/shadows are centred around neutral.
            if (mode == "emboss")
            {
                sumR += 0.5f;
                sumG += 0.5f;
                sumB += 0.5f;
            }

            // Edge detect / stroke modes may produce negative values
            if (mode is "edgeDetect" or "outline")
            {
                sumR = MathF.Abs(sumR);
                sumG = MathF.Abs(sumG);
                sumB = MathF.Abs(sumB);
            }

            // Mix with original
            if (mixRatio < 0.999f)
            {
                sumR = origR + (sumR - origR) * mixRatio;
                sumG = origG + (sumG - origG) * mixRatio;
                sumB = origB + (sumB - origB) * mixRatio;
            }

            var outA = preserveAlpha ? origA : Math.Clamp(MathF.Max(MathF.Max(MathF.Abs(sumR), MathF.Abs(sumG)), MathF.Abs(sumB)), 0f, 1f);

            result.SetPixel(x, y,
                Math.Clamp(sumR, 0f, 1f),
                Math.Clamp(sumG, 0f, 1f),
                Math.Clamp(sumB, 0f, 1f),
                outA);
        });

        return result;

    private static (float[] kernel, int size, float divisor) BuildKernel(string mode, int radius, float embossAngle)
    {
        switch (mode)
        {
            case "sharpen":
                return (new float[]
                {
                    0, -1, 0,
                    -1, 5, -1,
                    0, -1, 0
                }, 3, 1f);

            case "edgeDetect":
                return (new float[]
                {
                    -1, -1, -1,
                    -1, 8, -1,
                    -1, -1, -1
                }, 3, 1f);

            case "emboss":
            {
                // Directional emboss: center weight must be 0 so the original pixel is
                // removed from the sum. A +0.5 grey offset is added in Process() so that
                // flat areas map to mid-grey and the angle change is clearly visible.
                var cosA = MathF.Cos(embossAngle);
                var sinA = MathF.Sin(embossAngle);
                return (new float[]
                {
                    -cosA - sinA, -sinA, cosA - sinA,
                    -cosA, 0, cosA,
                    sinA - cosA, sinA, cosA + sinA
                }, 3, 1f);
            }

            case "engrave":
                return (new float[]
                {
                    -1, -1, 0,
                    -1, 0, 1,
                    0, 1, 1
                }, 3, 1f);

            case "gaussianBlur":
            {
                // Approximate Gaussian kernel
                var size = radius * 2 + 1;
                var kernel = new float[size * size];
                var sigma = radius * 0.5f + 0.5f;
                var sum = 0f;
                for (var ky = 0; ky < size; ky++)
                {
                    for (var kx = 0; kx < size; kx++)
                    {
                        var dx = kx - radius;
                        var dy = ky - radius;
                        var val = MathF.Exp(-(dx * dx + dy * dy) / (2f * sigma * sigma));
                        kernel[ky * size + kx] = val;
                        sum += val;
                    }
                }
                return (kernel, size, sum);
            }

            default: // "boxBlur" - box blur
            {
                var size = radius * 2 + 1;
                var kernel = new float[size * size];
                Array.Fill(kernel, 1f);
                return (kernel, size, size * size);
            }
        }
    }
}
